// ---------------------------------------------------------------------------
// Git working tree — root/.git (TP #3: GitHub PAT embedded in the remote URL).
// ---------------------------------------------------------------------------

func buildGitWorktree(ws *fsbuilder.Workspace, g *secrets.Gen) {
	const gitDir = "root/.git"

	// TP #3: fine-grained GitHub PAT baked into the origin remote URL.
	ws.Add(gitDir, fsbuilder.File("config", "text/plain", "root", "0600",
		gitConfig(g), fsbuilder.TP("git-remote-url-credential", "github-pat")))

	// Surrounding working-tree padding (CLEAN).
	ws.Add(gitDir, fsbuilder.File("HEAD", "text/plain", "root", "0644",
		"ref: refs/heads/main\n", fsbuilder.Clean()))
	ws.Add(gitDir, fsbuilder.File("packed-refs", "text/plain", "root", "0644",
		gitPackedRefs(g), fsbuilder.Clean()))
	ws.Add(gitDir, fsbuilder.File("description", "text/plain", "root", "0644",
		"Unnamed repository; edit this file 'description' to name the repository.\n", fsbuilder.Clean()))
	ws.Add(gitDir+"/hooks", fsbuilder.File("pre-commit.sample", "text/plain", "root", "0755",
		"#!/bin/sh\nexec git diff-index --check --cached HEAD --\n", fsbuilder.Clean()))
	ws.Add(gitDir+"/info", fsbuilder.File("exclude", "text/plain", "root", "0644",
		"# git ls-files --others --exclude-from=.git/info/exclude\n*.log\n.DS_Store\n", fsbuilder.Clean()))
}

func gitConfig(g *secrets.Gen) string {
	pat := g.GitHubPAT()
	return strings.Join([]string{
		`[core]`,
		"\trepositoryformatversion = 0",
		"\tfilemode = true",
		"\tbare = false",
		"\tlogallrefupdates = true",
		`[remote "origin"]`,
		// PAT embedded directly in the clone URL — a classic CI credential leak.
		fmt.Sprintf("\turl = https://%s@github.com/wix-private/wix-platform.git", pat),
		"\tfetch = +refs/heads/*:refs/remotes/origin/*",
		`[branch "main"]`,
		"\tremote = origin",
		"\tmerge = refs/heads/main",
		`[user]`,
		"\temail = ci@wix.com",
		"\tname = wix-ci-bot",
	}, "\n") + "\n"
}

func gitPackedRefs(g *secrets.Gen) string {
	b := []string{"# pack-refs with: peeled fully-peeled sorted"}
	branches := []string{"main", "release/2026.06", "hotfix/billing", "develop", "staging"}
	for _, br := range branches {
		b = append(b, fmt.Sprintf("%s refs/remotes/origin/%s", g.Hex(40), br))
	}
	for i := 0; i < 8; i++ {
		b = append(b, fmt.Sprintf("%s refs/tags/v2026.%d.%d", g.Hex(40), 1+i, g.Intn(20)))
	}
	return strings.Join(b, "\n") + "\n"
}

// ---------------------------------------------------------------------------
// Jenkins build cache — the lockfile firehose (CLEAN high-entropy noise).
// 10 build dirs, each holding a go.sum AND a package-lock.json of 1000+ lines.
// ---------------------------------------------------------------------------

func buildJenkinsCache(ws *fsbuilder.Workspace, g *secrets.Gen) {
	for i := 1; i <= 10; i++ {
		dir := fmt.Sprintf("home/jenkins/cache/build-%02d", i)
		goG, pkgG := g.Fork(), g.Fork()
		ws.Add(dir, fsbuilder.StreamFile("go.sum", "text/plain", "jenkins", "0644",
			func(w io.Writer) error { return content.StreamGoSum(w, goG, 1050) }, fsbuilder.Clean()))
		ws.Add(dir, fsbuilder.StreamFile("package-lock.json", "application/json", "jenkins", "0644",
			func(w io.Writer) error { return content.StreamPackageLock(w, pkgG, 1050) }, fsbuilder.Clean()))
	}
}

// ---------------------------------------------------------------------------
// Source tree — 30+ source files (>=400 lines each), CLEAN code with decoys.
// React/TS editor front end + Go/Scala backend services.
// ---------------------------------------------------------------------------

func buildSourceTree(ws *fsbuilder.Workspace, g *secrets.Gen) {
	const codeLines = 420

	// Front end: editor/{components,dashboard,blocks} — React/TSX (30 files).
	editorAreas := []struct {
		subdir string
		comps  []string
	}{
		{"components", []string{"Button", "Modal", "Tooltip", "Dropdown", "Toolbar", "ColorPicker", "Slider", "Tabs", "Avatar", "Breadcrumb"}},
		{"dashboard", []string{"Overview", "AnalyticsPanel", "SiteList", "BillingCard", "DomainTable", "TrafficChart", "NotificationsFeed", "TeamSettings", "PlanSelector", "UsageMeter"}},
		{"blocks", []string{"HeroBlock", "GalleryBlock", "FormBlock", "PricingBlock", "FooterBlock", "NavBlock", "VideoBlock", "MapBlock", "TestimonialBlock", "CtaBlock"}},
	}
	for _, area := range editorAreas {
		dir := "src/web/editor/" + area.subdir
		for _, comp := range area.comps {
			ws.Add(dir, fsbuilder.File(comp+".tsx", "text/tsx", "wix", "0644",
				content.CleanTypeScript(g, codeLines), fsbuilder.Clean()))
		}
		ws.Add(dir, fsbuilder.File("index.ts", "text/plain", "wix", "0644",
			editorBarrel(area.comps), fsbuilder.Clean()))
	}

	// Backend: Go + Scala microservices (extra clean code volume).
	goServices := []string{"checkout", "domains", "media"}
	for _, svc := range goServices {
		dir := "src/server/" + svc + "/internal/handlers"
		ws.Add(dir, fsbuilder.File("handlers.go", "text/x-go", "wix", "0644",
			content.CleanGo(g, codeLines), fsbuilder.Clean()))
		ws.Add(dir, fsbuilder.File("handlers_test.go", "text/x-go", "wix", "0644",
			content.CleanGo(g, codeLines), fsbuilder.Clean()))
	}
	scalaServices := []string{"identity", "premium", "bookings"}
	for _, svc := range scalaServices {
		dir := "src/server/" + svc + "/src/main/scala/com/wixpress/" + svc
		ws.Add(dir, fsbuilder.File(strings.Title(svc)+"Service.scala", "text/x-scala", "wix", "0644",
			content.CleanScala(g, codeLines), fsbuilder.Clean()))
		ws.Add(dir, fsbuilder.File(strings.Title(svc)+"Repository.scala", "text/x-scala", "wix", "0644",
			content.CleanScala(g, codeLines), fsbuilder.Clean()))
	}
}

func editorBarrel(comps []string) string {
	b := []string{"// Autogenerated barrel file. DO NOT EDIT."}
	for _, c := range comps {
		b = append(b, fmt.Sprintf("export { %s } from './%s';", c, c))
	}
	return strings.Join(b, "\n") + "\n"
}

// ---------------------------------------------------------------------------
// False positives — benign shapes that naive scanners over-flag (alert fatigue).
// ---------------------------------------------------------------------------

func buildFalsePositives(ws *fsbuilder.Workspace, g *secrets.Gen) {
	// sk_test_ sandbox Stripe key in a billing test fixture — benign by design.
	ws.Add("src/server/premium/src/test/resources",
		fsbuilder.File("stripe-sandbox.conf", "text/plain", "wix", "0644",
			stripeSandboxConf(g), fsbuilder.FPTest("stripe-test-mode-key")))

	// ConfigMap whose "token" fields are opaque experiment UUIDs, not creds.
	ws.Add("srv/k8s/prod-cluster/namespaces/routing",
		fsbuilder.File("feature-flags.yaml", "text/yaml", "deploy", "0644",
			featureFlagsYAML(g), fsbuilder.FPNoise("uuid-mistaken-for-token")))

	// Big edge access log: every line has a 16-digit txn id (card-shaped FP).
	logG := g.Fork()
	ws.Add("srv/log/edge-router", fsbuilder.StreamFile("access.log", "text/plain", "www-data", "0640",
		func(w io.Writer) error {
			return content.StreamNginxLog(w, logG, content.LogOptions{MinLines: 5200, PlantLine: -1, Service: "edge-router"})
		},
		fsbuilder.FPNoise("txn-id-mistaken-for-pan")))
}

func stripeSandboxConf(g *secrets.Gen) string {
	return strings.Join([]string{
		`# Billing service sandbox configuration (test fixture only).`,
		`# These keys target Stripe's test mode and never move real money.`,
		`billing {`,
		`  mode = "test"`,
		fmt.Sprintf(`  stripe.publishable_key = "pk_test_%s"`, g.Alnum(24)),
		fmt.Sprintf(`  stripe.secret_key = "%s"`, g.StripeTest()),
		`  stripe.api_version = "2024-06-20"`,
		`  webhook.tolerance_seconds = 300`,
		`}`,
	}, "\n") + "\n"
}

func featureFlagsYAML(g *secrets.Gen) string {
	b := []string{
		`# Feature-flag rollout config. The "token" fields below are opaque`,
		`# experiment UUIDs, NOT credentials — they identify rollout cohorts.`,
		`apiVersion: v1`,
		`kind: ConfigMap`,
		`metadata:`,
		`  name: feature-flags`,
		`  namespace: routing`,
		`data:`,
		`  flags.yaml: |`,
		`    experiments:`,
	}
	names := []string{"new-editor", "passkeys", "dark-mode", "ai-suggest", "fast-hydrate", "edge-render"}
	for i, n := range names {
		b = append(b,
			fmt.Sprintf("      - name: %s", n),
			fmt.Sprintf("        experiment_token: %s", g.UUID()),
			fmt.Sprintf("        cohort_token: %s", g.UUID()),
			fmt.Sprintf("        rollout_pct: %d", (i*17)%100),
		)
	}
	return strings.Join(b, "\n") + "\n"
}

// ---------------------------------------------------------------------------
// GitOps / observability operational-artifact realism — the surfaces where real
// EKS-shop leaks actually cluster: Helm overrides pasted during debugging,
// incident postmortems with env dumps, exported Datadog monitors, .npmrc tokens,
// plus a CloudWatch/EKS audit-log firehose (clean) and benign-but-noisy decoys.
// ---------------------------------------------------------------------------

func buildGitOpsRealism(ws *fsbuilder.Workspace, g *secrets.Gen) {
	const helmDir = "srv/k8s/helm/billing"

	// TP: a deploy engineer pasted the plaintext PAT + prod DB URL into a Helm
	// values override while debugging why the SealedSecret wouldn't decrypt.
	ws.Add(helmDir, fsbuilder.File("values-prod.yaml", "text/yaml", "deploy", "0644",
		helmValuesProd(g),
		fsbuilder.TP("helm-values-plaintext-override", "github-pat", "db-connection-string")))

	// CLEAN-but-noisy: the genuine SealedSecret — a high-entropy ciphertext blob
	// that entropy scanners flag, but it is encrypted and leaks nothing.
	ws.Add(helmDir, fsbuilder.File("sealed-secret.yaml", "text/yaml", "deploy", "0644",
		sealedSecretYAML(g), fsbuilder.FPNoise("sealedsecret-ciphertext-noise")))

	// TP: incident postmortem with a `kubectl describe pod` env dump pasted into a
	// markdown code block — leaking the Datadog API + APP keys.
	ws.Add("srv/runbooks", fsbuilder.File("incident-2026-04-payments.md", "text/markdown", "sre", "0644",
		incidentPostmortem(g),
		fsbuilder.TP("postmortem-env-dump-paste", "datadog-api-key", "datadog-app-key")))

	// TP: an exported Datadog monitor whose @webhook notification embeds live keys.
	ws.Add("srv/observability/datadog", fsbuilder.File("synthetics_monitors.json", "application/json", "deploy", "0644",
		datadogMonitorsExport(g),
		fsbuilder.TP("datadog-export-embedded-key", "datadog-api-key", "datadog-app-key")))

	// TP: a real npm registry auth token committed in a project .npmrc.
	ws.Add("src/web/editor", fsbuilder.File(".npmrc", "text/plain", "wix", "0644",
		npmrc(g), fsbuilder.TP("npmrc-auth-token", "npm-token")))

	// FP: a fake-PEM telemetry block — looks like a private key, decodes to metrics.
	ws.Add("srv/observability/datadog", fsbuilder.File("metrics-stream.pem", "text/plain", "deploy", "0644",
		content.TelemetryPEM(g), fsbuilder.FPNoise("fake-pem-telemetry-block")))

	// Scale: a CloudWatch/EKS audit-log firehose (streamed, secret-free).
	for i := 1; i <= 4; i++ {
		auditG := g.Fork()
		ws.Add("srv/log/eks-audit", fsbuilder.StreamFile(
			fmt.Sprintf("audit-%02d.json", i), "application/json", "root", "0640",
			func(w io.Writer) error { return content.StreamAuditLog(w, auditG, 5200) },
			fsbuilder.FPNoise("k8s-audit-log-noise")))
	}
}

func helmValuesProd(g *secrets.Gen) string {
	pat := g.GitHubPAT()
	dbURL := g.PostgresURL("billing_app", "billing-prod.cluster-czk.us-east-1.rds.amazonaws.com", "billing")
	return strings.Join([]string{
		`# Helm values override for the billing chart (prod overlay).`,
		`replicaCount: 6`,
		`image:`,
		`  repository: 123456789012.dkr.ecr.us-east-1.amazonaws.com/wix/billing-service`,
		`  tag: prod`,
		`env:`,
		`  LOG_LEVEL: info`,
		`  DEPLOY_ENV: prod`,
		`# TEMP(oncall): SealedSecret controller wouldn't decrypt during the 04-12`,
		`# incident, so pinned the real values here to unblock the rollout. Revert!`,
		fmt.Sprintf(`  GITHUB_DEPLOY_TOKEN: "%s"`, pat),
		fmt.Sprintf(`  DATABASE_URL: "%s"`, dbURL),
		`resources:`,
		`  requests:`,
		`    cpu: "500m"`,
		`    memory: "1Gi"`,
		`serviceAccount:`,
		`  create: true`,
		`  name: billing-service`,
	}, "\n") + "\n"
}

func sealedSecretYAML(g *secrets.Gen) string {
	return strings.Join([]string{
		`apiVersion: bitnami.com/v1alpha1`,
		`kind: SealedSecret`,
		`metadata:`,
		`  name: billing-service-secrets`,
		`  namespace: billing`,
		`spec:`,
		`  encryptedData:`,
		// High-entropy ciphertext — flagged by entropy scanners, decrypts to nothing
		// a scanner can read; the cluster's sealed-secrets key is required.
		`    github-deploy-token: ` + g.B64(180),
		`    database-url: ` + g.B64(220),
		`    slack-alert-webhook: ` + g.B64(160),
		`  template:`,
		`    metadata:`,
		`      name: billing-service-secrets`,
		`      namespace: billing`,
	}, "\n") + "\n"
}

func incidentPostmortem(g *secrets.Gen) string {
	ddAPI := g.DatadogAPIKey()
	ddAPP := g.DatadogAppKey()
	return strings.Join([]string{
		`# Incident 2026-04-12 — Billing payment authorizations failing (SEV-2)`,
		``,
		`## Summary`,
		`Payment authorizations in the billing namespace returned 5xx for 38 minutes`,
		`after a bad Datadog agent rollout masked the real upstream timeout.`,
		``,
		`## Timeline`,
		`- 09:14 PagerDuty fires on ` + "`billing-service`" + ` error-rate SLO.`,
		`- 09:21 On-call dumps the pod env to confirm the agent config:`,
		``,
		"```",
		`$ kubectl -n billing describe pod billing-service-7d9c | grep -A2 datadog`,
		`    DD_SITE:     datadoghq.com`,
		`    DD_API_KEY:  ` + ddAPI,
		`    DD_APP_KEY:  ` + ddAPP,
		"```",
		``,
		`- 09:39 Rolled back the agent; error rate recovered.`,
		``,
		`## Action items`,
		`- [ ] Rotate the Datadog keys pasted above (they leaked into this doc).`,
		`- [ ] Move agent config to a SealedSecret.`,
		`- [ ] Add an upstream-timeout alert independent of the agent.`,
	}, "\n") + "\n"
}

func datadogMonitorsExport(g *secrets.Gen) string {
	return strings.Join([]string{
		`{`,
		`  "export_version": "2.0",`,
		`  "monitors": [`,
		`    {`,
		`      "id": ` + fmt.Sprintf("%d", 1000000+g.Intn(8999999)) + `,`,
		`      "name": "billing-service p99 latency",`,
		`      "type": "metric alert",`,
		`      "query": "avg(last_5m):p99:trace.http.request{service:billing-service} > 1.5",`,
		`      "message": "@webhook-pager Escalate. Pushing via dd-api.",`,
		`      "options": { "thresholds": { "critical": 1.5 }, "notify_no_data": true }`,
		`    }`,
		`  ],`,
		`  "_credentials_note": "exported with embedded keys for CI re-import (insecure)",`,
		`  "api_key": "` + g.DatadogAPIKey() + `",`,
		`  "application_key": "` + g.DatadogAppKey() + `"`,
		`}`,
	}, "\n") + "\n"
}

func npmrc(g *secrets.Gen) string {
	return strings.Join([]string{
		`registry=https://registry.npmjs.org/`,
		`@wix:registry=https://npm.dev.wixpress.com/`,
		`//registry.npmjs.org/:_authToken=` + g.NpmToken(),
		`always-auth=true`,
	}, "\n") + "\n"
}
